import React from 'react';
import Lottie from 'lottie-react';
import rocketLottie from '../assets/rocket-lottie.json';

export default function HeroSection() {
  return (
    <section style={{display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',minHeight:'60vh',padding:'2rem 0'}}>
      <div className="glass-card" style={{textAlign:'center',maxWidth:600}}>
        <Lottie animationData={rocketLottie} loop={true} autoplay style={{width:220,margin:'0 auto 1.5rem'}} />
        <h1 style={{fontSize:'2.6rem',fontWeight:800,marginBottom:'0.5rem',letterSpacing:'-1px',color:'var(--primary)'}}>AI Quiz Builder</h1>
        <h2 style={{fontSize:'1.45rem',fontWeight:500,marginBottom:'1.2rem',color:'#334155',lineHeight:1.3}}>
          Create, customize, and analyze quizzes with <span style={{color:'var(--accent)',fontWeight:700}}>AI superpowers</span>.<br/>
          <span style={{fontWeight:400}}>Beautiful. Fast. Interactive.</span>
        </h2>
        <button style={{fontSize:'1.2rem',padding:'0.9rem 2.2rem',background:'var(--primary)',borderRadius:'2rem',boxShadow:'0 2px 12px #c7d2fe',fontWeight:700,letterSpacing:'0.5px'}} onClick={()=>window.location.href='/create'}>
          🚀 Start Creating
        </button>
      </div>
    </section>
  );
}
